-- ============================================
-- Legislacao full-site: cicero-lucena / Senado / projetos_lei
-- Seed completo do recorte: autoria parlamentar substantiva Senado 2007-2014
-- ============================================
-- Fonte oficial: Senado Federal Dados Abertos
--   https://legis.senado.leg.br/dadosabertos/senador/4529/autorias.json
--   https://legis.senado.leg.br/dadosabertos/materia/{codigo}.json
--   https://legis.senado.leg.br/dadosabertos/materia/autoria/{codigo}.json
--   https://www25.senado.leg.br/web/atividade/materias/-/materia/{codigo}
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = cicero-lucena-senado-completo-autoria-substantiva-2007-2014-20260505
--   coverage_scope = inventario_completo_senado_autoria_substantiva_2007_2014_20260505
--
-- Filtro factual: endpoint senador/4529/autorias.json com
--   IndicadorAutorPrincipal=Sim, siglas substantivas em
--   (PLS, PL, PEC, PLP, PRS, PDL, PDS, PCE), e endpoint
--   materia/autoria/{codigo}.json confirmando CodigoParlamentar=4529
--   com NumOrdemAutor=1. Resultado deste snapshot: 51 rows.
--
-- O recorte e completo apenas para a autoria parlamentar substantiva no Senado
-- retornada pelo endpoint oficial. Nao e inventario completo da vida publica do
-- candidato.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO escreve em historico_politico.
-- Esta migration NAO popula tema, destaque, destaque_motivo nem situacao
--   (campos editoriais/curatoriais, fora do contrato bruto de ingest oficial).
-- Esta migration NAO promove UI/whitelist publica; isso exige novo fechamento.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  target_count int;
  mandato_senado_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'cicero-lucena';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'cicero-lucena: candidato ausente neste banco local/CI minimo; seed projetos_lei Senado pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'cicero-lucena-senado-completo-autoria-substantiva-2007-2014-20260505';

  IF projetos_total NOT IN (0, 51) THEN
    RAISE EXCEPTION 'Pre-condicao cicero-lucena: esperadas 0 rows atuais ou 51 rows alvo idempotentes em projetos_lei, encontradas %', projetos_total;
  END IF;

  IF projetos_total = 51 AND target_count <> 51 THEN
    RAISE EXCEPTION 'Pre-condicao cicero-lucena: 51 rows existentes, mas apenas % com coverage_id alvo', target_count;
  END IF;

  SELECT count(*) INTO mandato_senado_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
    AND UPPER(COALESCE(hp.estado, '')) = 'PB'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2007
    AND COALESCE(hp.periodo_fim, 0) >= 2014;

  IF mandato_senado_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao cicero-lucena: mandato Senado/PB 2007-2014 nao encontrado em historico_politico';
  END IF;
END $$;

