WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'cicero-lucena'
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _seed_cicero_lucena_senado_lote_a_projetos AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO NOTHING;

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  target_count int;
  scope_count int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'cicero-lucena';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'cicero-lucena: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Senado'
    AND proposicao_id_api IN ('79936', '80338', '80409', '81590', '81922', '82193', '82583', '87663', '87662', '89958', '89951', '90098', '90253', '92415', '92977', '95075', '97593', '102269', '102320', '102565', '102566', '103387', '104782', '104822', '104837', '105611', '105921', '106017', '106454', '106462', '108442', '108441', '111182', '112843', '111979', '113339', '113567', '114133', '114132', '114134', '115153', '115885', '115886', '115887', '115889', '115891', '115893', '115894', '118241', '119419', '119418');

  SELECT count(*) INTO scope_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'cicero-lucena-senado-completo-autoria-substantiva-2007-2014-20260505'
    AND coverage_scope = 'inventario_completo_senado_autoria_substantiva_2007_2014_20260505';

  SELECT count(*) INTO lme_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  IF target_count <> 51 THEN
    RAISE EXCEPTION 'Pos-apply cicero-lucena: esperadas 51 rows alvo Senado em projetos_lei, encontradas %', target_count;
  END IF;

  IF total_count <> 51 THEN
    RAISE EXCEPTION 'Pos-apply cicero-lucena: total projetos_lei esperado 51, encontrado %', total_count;
  END IF;

  IF scope_count <> 51 THEN
    RAISE EXCEPTION 'Pos-apply cicero-lucena: esperadas 51 rows com coverage_id/scope alvo, encontradas %', scope_count;
  END IF;

  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply cicero-lucena: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;

  RAISE NOTICE 'Pos-apply cicero-lucena Senado Lote A: projetos_lei=% coverage_scope=% legislacao_mandato_executivo=%', total_count, scope_count, lme_count;
END $$;
